// src/index.ts
import { z } from "zod";
var BaseGameLogic = class {
  serializeState(state) {
    return JSON.stringify(state);
  }
  deserializeState(data) {
    return JSON.parse(data);
  }
  generateStatePrompt(perspective) {
    return defaultStatePromptGenerator(perspective);
  }
  cloneState(state) {
    return JSON.parse(JSON.stringify(state));
  }
};
var SPECTATOR_ROLE_ID = "nexus_reserved_specator";
function isSpectator(roleId) {
  return roleId === SPECTATOR_ROLE_ID;
}
function defaultStatePromptGenerator(perspective) {
  return JSON.stringify(perspective);
}
function cloneState(state) {
  return JSON.parse(JSON.stringify(state));
}
function validateAction(action, spec) {
  return { valid: true };
}
function isMultiPlayerCountConfig(roleIds) {
  return typeof roleIds === "object" && roleIds !== null && !Array.isArray(roleIds);
}
function getRoleIdsForPlayerCount(roleIds, playerCount) {
  if (!roleIds) return [];
  if (Array.isArray(roleIds)) return roleIds;
  if (playerCount && roleIds[playerCount]) return roleIds[playerCount];
  return [];
}
function getAvailablePlayerCounts(roleIds) {
  if (!roleIds) return [];
  if (Array.isArray(roleIds)) return [roleIds.length];
  return Object.keys(roleIds).map(Number);
}
function getGameStatusText(metadata, perspective) {
  if (metadata.getStatusText) return metadata.getStatusText(perspective);
  return "Game in progress";
}
var stateSerializer = {
  serializeSet(set) {
    return Array.from(set);
  },
  deserializeSet(arr) {
    return new Set(arr);
  },
  serializeMap(map) {
    return Array.from(map.entries());
  },
  deserializeMap(entries) {
    return new Map(entries);
  },
  jsonReplacer(_key, value) {
    return value;
  },
  jsonReviver(_key, value) {
    return value;
  },
  stringify(value) {
    return JSON.stringify(value);
  },
  parse(text) {
    return JSON.parse(text);
  }
};
export {
  BaseGameLogic,
  SPECTATOR_ROLE_ID,
  cloneState,
  defaultStatePromptGenerator,
  getAvailablePlayerCounts,
  getGameStatusText,
  getRoleIdsForPlayerCount,
  isMultiPlayerCountConfig,
  isSpectator,
  stateSerializer,
  validateAction,
  z
};
